// Read reads data from the Data reader.
//
// Kept to satisfy the io.Reader interface.
func (s UploadCustomPlaylistCoverReq) Read(p []byte) (n int, err error) {
	if s.Data == nil {
		return 0, io.EOF
	}
	return s.Data.Read(p)
}
